using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
vector<int> ans;
void dfs(int s)
{
	if(s==0)
	{
		if(ans.size()==1)return;
		cout<<ans[0];
		for(int i=1;i<ans.size();++i)
		{
			cout<<'+'<<ans[i];
		}
		puts("");
		return;
	}
	int begin=0;
	if(ans.empty())
	{
		begin=1;
	}
	else
	{
		begin=ans.back();
	}
	for(int i=begin;i<=s;++i)
	{
		ans.push_back(i);
		dfs(s-i);
		ans.pop_back();
	}
	return;
}
int n;
int main(void)
{
	//freopen("xx.in","r",stdin);
